module adder_8bit
(
    input [7:0] a,
    input [7:0] b,
    input cin,
    output [7:0] sum,
    output cout
);
    // YOUR CODE HERE
    // TIPS:
    //   You may copy the declaration of adder_1 from handout file.
    //   You may use operator "+" for adder_8bit, but remember to compare with the table in handout.
    //   You may use "assign" statement for combinational logic.
    wire cout0, cout1, cout2, cout3, cout4, cout5, cout6;
    wire [7:0] s;
    wire [6:0] s0;
    wire [5:0] s1;
    wire [4:0] s2;
    wire [3:0] s3;
    wire [2:0] s4;
    wire [1:0] s5;
    wire s6;
    assign {cout0, s[0]} = a[0] + b[0] + cin;
    assign {cout1, s[1]} = a[1] + b[1] + cout0;
    assign {cout2, s[2]} = a[2] + b[2] + cout1;
    assign {cout3, s[3]} = a[3] + b[3] + cout2;
    assign {cout4, s[4]} = a[4] + b[4] + cout3;
    assign {cout5, s[5]} = a[5] + b[5] + cout4;
    assign {cout6, s[6]} = a[6] + b[6] + cout5;
    assign {cout, s[7]} = a[7] + b[7] + cout6;
    assign sum = s;
endmodule
